data.query:
mutation giftCardCreate($input: GiftCardCreateInput!) {
    giftCardCreate(input: $input) {
        giftCard {
            id
            balance {
                amount
                currencyCode
            }
            initialValue {
                amount
                currencyCode
            }
            expiresOn
            note
            customer {
                id
            }
            enabled
            createdAt
            updatedAt
            lastCharacters
            maskedCode
            templateSuffix
        }
        giftCardCode
        userErrors {
            message
            field
            code
        }
    }
}
